import json

with open("/root/books/webapp/books.json", "r", encoding="utf-8") as f:
    books = json.load(f)

updates = {
563: {
    0: "Проверь: когда ты говоришь ребёнку что любишь его? Только когда он сделал что-то хорошее — или вне зависимости от поведения? Разница определяет что он усваивает о своей ценности. Ребёнок которого хвалят за достижения получает послание: я ценен когда успешен. Ребёнок которого любят вне зависимости от результата получает послание: я ценен сам по себе. Из этого послания вырастает либо человек с внутренней опорой — либо человек который всю жизнь доказывает.",
    1: "Замени «молодец» на описание и вопрос: «ты нарисовал очень детальный рисунок — что тебе больше всего нравится в нём?» Это переключает фокус с твоей оценки на его внутреннее ощущение от работы. Ребёнок который привык получать «молодец» начинает рисовать для оценки — а не потому что ему интересно. Ребёнок которого спрашивают о его ощущениях учится прислушиваться к себе. Это разница между внешней и внутренней мотивацией которая проявится во всей взрослой жизни.",
    2: "Платить ребёнку за хорошие оценки или давать конфеты за уборку — краткосрочно работает. Долгосрочно убивает интерес к учёбе и помощи по дому как таковым. Ищи способы поддержать внутренний интерес — а не заменить его внешней наградой. Это не значит что нельзя никогда ничего давать — значит что вознаграждение за уже приятное занятие убивает приятность. Задай вопрос: «ему это нравится само по себе?» — и если да, не превращай это в задание за деньги.",
    3: "Базовое убеждение о природе ребёнка определяет весь твой подход к воспитанию. Если веришь что дети в основе хорошие — воспитываешь иначе чем если считаешь что их природу нужно подавлять. Посмотри честно: какое убеждение лежит в основе твоих реакций на трудное поведение ребёнка? Ты реагируешь как на человека который чего-то не умеет — или как на противника которого нужно победить? Ответ на этот вопрос скажет больше чем любая техника.",
    4: "Спрашивай ребёнка его мнение о правилах — не как формальность. Объясняй почему правило существует. Ребёнок который понимает смысл правила соблюдает его изнутри, а не из страха наказания. Это не занимает намного больше времени — но создаёт принципиально другой тип отношений. Ребёнок который воспитывается через смысл а не через страх вырастает человеком который следует ценностям а не только правилам. Когда правил нет рядом — ценности остаются.",
    5: "«Я люблю тебя и сейчас твоё поведение неприемлемо» — две части одного высказывания. Первая создаёт безопасность в которой ребёнок может услышать вторую. Многие родители боятся что выражение любви в момент плохого поведения «поощряет» его. Но любовь и граница — не противоречие. Граница без любви — это страх. Любовь без границы — это хаос. Вместе они создают среду в которой ребёнок чувствует себя в безопасности и при этом знает что приемлемо.",
    6: "Тайм-аут работает как краткосрочный инструмент остановки поведения — но не учит ничему. Если используешь его — обязательно добавляй «тайм-ин» после: разговор о том что произошло и что делать иначе. Тайм-аут без тайм-ина — это изоляция. Тайм-аут с тайм-ином — это пауза перед обучением. Разница определяет что ребёнок усваивает: «когда я плохо себя веду меня оставляют одного» или «когда я плохо себя веду мы вместе разбираемся что произошло».",
    7: "Школьные оценки — не показатель любви к знаниям. Поддерживай любопытство ребёнка вне оценочной системы: вопросы, эксперименты, книги по интересу, а не по программе. Ребёнок который получает пятёрки но ненавидит учиться — не образован в смысле который важен. Ребёнок который любит узнавать новое но получает тройки — будет учиться всю жизнь. Твоя задача не защитить оценки а защитить любопытство. Оно ценнее.",
    8: "Читай авторов которые оспаривают то что ты считаешь само собой разумеющимся — в воспитании и в любой другой области. Дискомфорт от чтения Кона часто означает что он попал в точку. Самые важные книги — те которые вызывают не согласие а вопрос. Согласие подтверждает то что ты уже знаешь. Вопрос открывает то что ты не замечал. Родитель который читает только то с чем согласен — не развивается. Родитель который читает неудобное — меняется.",
    9: "Проверяй методы воспитания на соответствие долгосрочной цели. Что именно ты формируешь этим методом — прямо сейчас? Послушание сейчас или автономию через 15 лет? Обе цели несовместимы в одном методе. Задай себе вопрос раз в несколько месяцев: каким я хочу видеть своего ребёнка в 25 лет? Какие качества для этого нужны? Что из того что я делаю сейчас формирует эти качества — а что работает против них? Это упражнение меняет приоритеты.",
},
564: {
    0: "Логика работает лучше угроз потому что показывает причинно-следственные связи которые действуют всю жизнь. Угрозы работают пока есть тот кто угрожает — и исчезают вместе с ним. Подросток которого воспитывали через угрозы теряет тормоза когда уходит из дома. Подросток которого воспитывали через логику последствий несёт этот механизм с собой. Разница в том что остаётся когда тебя нет рядом — а именно это и есть воспитание.",
    1: "«Как жаль» с искренним сочувствием — одна из самых мощных фраз в воспитании. Она сохраняет связь и одновременно позволяет последствию сделать свою работу. Сочувствие без последствия — это спасение. Последствие без сочувствия — это холодное наказание. Вместе они говорят ребёнку: я на твоей стороне и при этом реальность устроена именно так. Это точная копия того как устроен мир за пределами дома.",
    2: "Позволяй ребёнку совершать небольшие ошибки с небольшими последствиями сейчас. Это инвестиция: каждая усвоенная ошибка в 7 лет — это предотвращённая катастрофа в 25. Родитель который защищает ребёнка от всех ошибок отправляет его во взрослую жизнь без опыта падения и вставания. Первое серьёзное падение в 25 — без этого опыта — может быть разрушительным. Ошибки в безопасной среде детства — это тренировочный зал для взрослой жизни.",
    3: "Замени команды вопросами: не «убери комнату» а «когда ты планируешь убрать комнату?». Ответственность за решение переходит к ребёнку вместе с вопросом. Это небольшой сдвиг в языке — но большой сдвиг в том кто несёт ответственность. Ребёнок который сам назвал время убирает чаще чем ребёнок которому приказали. Потому что это его слово а не твоё требование. Попробуй эту технику неделю и понаблюдай за результатом.",
    4: "Формулируй правила через то что ты делаешь а не через угрозы того что сделаешь с ребёнком. «Я играю с тобой когда ты говоришь спокойно» работает лучше «если не успокоишься — накажу». Первое даёт ребёнку контроль над результатом. Второе создаёт противостояние где он либо подчиняется либо продолжает сопротивляться. Контроль через собственное поведение — не слабость. Это чистая логика последствий без личной угрозы.",
    5: "Каждый раз когда ты решаешь проблему за ребёнка вместо того чтобы помочь ему решить самому — ты берёшь у него опыт который ему понадобится. Любовь которая мешает учиться на ошибках — не любовь, а страх. Родители-вертолёты обычно добрые и заботливые люди — которые боятся видеть ребёнка в дискомфорте. Но именно дискомфорт — учитель. Твоя задача не убрать дискомфорт а быть рядом пока ребёнок с ним справляется.",
    6: "Споры о правилах каждый день — это трата энергии на симптомы а не на причины. Установи ясные логические последствия один раз — и перестань тратить энергию на ежедневные переговоры. Ежедневные переговоры обучают ребёнка что правила — это отправная точка для торговли. Ясное последствие обучает что правила — это описание реальности. «Если ты делаешь X — происходит Y» — не угроза, это информация о том как устроен мир.",
    7: "Принципы Love and Logic работают не только с детьми — с любым человеком которому нужно принять ответственность за своё поведение. Сочувствие плюс последствие — универсальная формула. Попробуй применить её в разговоре с коллегой или партнёром. «Как жаль что так получилось» — и молчание. Без совета, без объяснения, без спасения. Часто этого достаточно чтобы человек сам нашёл выход — и это его выход, не твой.",
    8: "«Я подумаю и скажу тебе позже» — не слабость и не откладывание. Это осознанный выбор реагировать из верхнего мозга а не из нижнего. Решения принятые в спокойствии работают лучше решений принятых в ярости. Когда ты замечаешь что сейчас можешь сказать что-то что потом пожалеешь — «я подумаю» это твоя пауза. Используй её. Через час ты часто находишь решение которое в момент конфликта было невозможно заметить.",
    9: "Лучшие методы воспитания — те которые авторы проверили на своих детях. Не на идеальных детях из исследований — на реальных, трудных, обычных. Доверяй опыту подкреплённому личной практикой. Читая книги о воспитании задавай вопрос: «этот автор применял это дома?» Теория которая не прошла проверку кухней и подростковыми ужинами — неполная. Фэй применял — и именно поэтому его советы конкретны и устойчивы к реальным возражениям.",
},
565: {
    0: "Проверь — какие из пяти посланий твой ребёнок слышит регулярно. Какое он не слышит никогда? Это и есть место для работы. Пять посланий по Грею: «ты в безопасности», «ты любим», «ты хорош», «ты нужен», «ты не один». Каждое закрывает базовую психологическую потребность. Потребность которую не закрыли в детстве человек будет закрывать всю взрослую жизнь — иногда деструктивными способами. Знать какое послание недоставало — значит знать где лечить.",
    1: "Страх что без наказаний ребёнок выйдет из-под контроля — обоснован только если единственный инструмент контроля — страх. Если есть доверие и последствия — страх не нужен. Дети ведут себя хорошо не потому что боятся — а потому что хотят соответствовать ожиданиям людей которым доверяют. Авторитет основанный на уважении устойчивее авторитета основанного на страхе. Страх работает пока есть наказание. Уважение работает даже когда тебя нет рядом.",
    2: "За нытьём всегда есть чувство или потребность. Назови их — и нытьё теряет смысл. Это требует от тебя остановиться и послушать а не просто выдать команду замолчать. «Ты устал и хочешь есть — это тяжело» — и ребёнок часто успокаивается не потому что получил еду, а потому что его поняли. Нытьё — это неумелая коммуникация. Твоя задача не заглушить её а помочь стать умелой. Это инвестиция которая окупится когда ему будет 16 лет.",
    3: "Наблюдай за своим ребёнком: что его перегружает и что заряжает? Что снижает его сопротивление а что усиливает? Адаптируй подход к конкретному человеку а не к усреднённому «ребёнку из книги». Книги о воспитании дают принципы — не инструкции. Принцип работает всегда. Конкретная техника работает для конкретного ребёнка. Ты единственный кто знает своего ребёнка достаточно хорошо чтобы адаптировать принцип под него. Это и есть родительское искусство.",
    4: "Создай ребёнку физическое место куда можно уйти когда эмоции зашкаливают. Не комната позора — место восстановления. Когда он научится использовать его сам — ты дал ему инструмент на всю жизнь. Взрослые которые умеют создавать себе пространство для восстановления — более устойчивы. Они знают: когда перегружен — нужна пауза, а не продолжение в состоянии срыва. Этот навык закладывается именно через такие места в детстве.",
    5: "Признай желание — откажи в его исполнении. Это два разных действия которые можно делать одновременно. Признание желания не обязывает тебя его выполнять. «Ты хочешь мороженое — я понимаю, это вкусно. Сейчас нет.» Первая часть — признание. Вторая — граница. Ребёнок получает оба послания: меня понимают и при этом не всё что я хочу происходит немедленно. Это точное описание реальности которое готовит его к взрослой жизни.",
    6: "Предупреждение за 5-10 минут перед сменой деятельности снижает сопротивление потому что даёт мозгу время подготовиться к переходу. Это не уступка — это понимание нейробиологии. Мозг ребёнка — да и взрослого — не любит внезапных переключений. «Через 10 минут уходим» это не баловство. Это сигнал который позволяет мозгу начать процесс завершения. Без него ребёнок переживает отрыв как насилие. С ним — как плановый переход.",
    7: "Отцовский вклад в воспитание — не помощь матери и не повторение её стиля. Это отдельный и необходимый вклад. Физические игры, приключения, умеренный риск — это отцовская область которую нельзя ничем заменить. Дети которые играли физически с отцом лучше управляют своими эмоциями в социальных ситуациях. Не потому что папа хороший — а потому что физическая игра с правилами учит регулировать возбуждение. Это специфический вклад который создаётся именно в этом типе взаимодействия.",
    8: "Не сравнивай масштаб детского горя со взрослым. Для ребёнка это настоящее горе с настоящей болью. Признай его — и ты учишь ребёнка доверять своему внутреннему миру. Ребёнок которому говорили «это мелочи» учится не доверять своим ощущениям. Он вырастает человеком который обесценивает собственный опыт — или наоборот ищет у других разрешения на то что он вправе чувствовать. Признание детского горя — это не потакание. Это строительство внутреннего компаса.",
    9: "Твоя главная задача не научить ребёнка всему — а быть надёжной базой к которой он может вернуться. Надёжность этой базы определяет насколько далеко он решится уйти. Ребёнок с надёжной базой рискует, исследует, пробует — потому что знает: если упадёт, есть куда вернуться. Ребёнок без надёжной базы либо не уходит совсем либо уходит и не возвращается. Быть надёжной базой — не значит быть идеальным. Значит быть предсказуемым и доступным.",
},
566: {
    0: "Богатая речевая среда, разнообразные физические ощущения, эмоциональная отзывчивость в первые три года — это строительные материалы мозга. Не нужны дорогие игрушки: нужны разговоры, игры, объятия и безопасность. Всё что ты делаешь в эти годы буквально формирует нейронные пути которые будут работать всю жизнь. Это не значит что нужно постоянно «развивать» — нужно быть рядом и реагировать. Именно отзывчивость взрослого на сигналы ребёнка — самый мощный строительный материал.",
    1: "Разговаривай с ребёнком постоянно — даже когда он ещё не понимает слов. Описывай что делаешь, что видишь, что чувствуешь. Это самая дешёвая и самая эффективная инвестиция в интеллект ребёнка. «Мы идём в магазин. Я вижу красные яблоки. Хочешь потрогать?» — это не глупо. Это строительство мозга. Дети с богатым языковым окружением в первые годы демонстрируют преимущества в обучении которые сохраняются на десятилетия.",
    2: "Ограничение двигательной активности ребёнка ради «развивающих занятий» — ошибочная стратегия. Движение это не перерыв от развития — это часть развития. Ребёнок которого отпускают бегать учится лучше ребёнка которого удерживают за партой. Мозжечок — центр движения — напрямую связан с когнитивными функциями. Физическая активность улучшает концентрацию, память и способность к обучению. Перемена — не потеря учебного времени. Это инвестиция в качество следующего урока.",
    3: "Качество эмоционального климата в доме влияет на мозг ребёнка напрямую. Даже если споры с партнёром происходят «после того как ребёнок заснул» — стресс в атмосфере считывается детьми. Здоровые отношения родителей — это инвестиция в мозг ребёнка. Кортизол — гормон стресса — в хроническом состоянии буквально разрушает нейронные связи в гиппокампе. Ребёнок живущий в атмосфере хронического стресса имеет меньший ресурс для обучения и регуляции. Лучшее что ты можешь сделать для мозга ребёнка — работать над климатом в семье.",
    4: "Экран не развивает ребёнка до двух лет — он занимает его внимание вместо реального развития. Замени экранное время разговорами, физическими играми, чтением вслух. Это не ретроградность — это нейронаука. Мозг ребёнка развивается через живое взаимодействие — через отклик реального человека на его сигналы. Экран отвечает всегда одинаково независимо от того что делает ребёнок. Это не развитие — это пассивное поглощение. После двух лет ситуация меняется — но в первые годы живое важнее цифрового.",
    5: "Музыкальный инструмент для ребёнка — не роскошь и не способ развить «творческий потенциал». Это тренировка когнитивных функций которые переносятся на математику, логику и исполнительные функции. Игра на инструменте требует одновременной координации рук, чтения нотного текста, слухового контроля и памяти. Это одна из наиболее комплексных когнитивных задач. Любой инструмент — не только фортепьяно. Главное регулярность и удовольствие от процесса.",
    6: "20 минут чтения вслух перед сном каждый день — это дешевле любого развивающего курса и эффективнее большинства из них. Это работает с любого возраста — и продолжает работать когда ребёнок уже умеет читать сам. Ритуал чтения перед сном делает несколько вещей одновременно: обогащает словарный запас, создаёт время близости, успокаивает нервную систему перед сном, формирует любовь к историям. Это один из самых высококвалифицированных 20 минут которые ты можешь провести с ребёнком.",
    7: "Режим сна ребёнка — это не педагогическая рекомендация, это нейробиологическая необходимость. Жёсткий режим отхода ко сну это инвестиция в мозг — не ограничение свободы. Во время сна мозг ребёнка консолидирует полученные за день знания и очищается от метаболических отходов. Недосыпающий ребёнок хуже учится, хуже регулирует эмоции и медленнее восстанавливается после стресса. Борьба за режим сна — одна из самых важных и самых недооценённых задач родителя.",
    8: "Развитие эмоционального интеллекта у ребёнка важнее подготовки к школьным тестам. Называй эмоции, обсуждай чувства других, читай книги с морально сложными персонажами — это формирует навыки которые определят качество его жизни. EQ предсказывает успех в жизни лучше IQ. Не потому что IQ не важен — а потому что без способности управлять отношениями и собственными эмоциями интеллект не раскрывается полностью. Эмоциональный интеллект тренируется — и именно ты первый тренер.",
    9: "Большинство советов по воспитанию — это мнения переданные от поколения к поколению. Небольшое количество из них подкреплено реальными исследованиями. Задавай вопрос: «это доказано или просто принято считать?» Медина помогает различать одно от другого. Это не значит игнорировать традицию — значит проверять её. Некоторые традиционные практики подтверждаются наукой. Некоторые опровергаются. Знание разницы позволяет сохранять первые и отпускать вторые без чувства вины.",
},
567: {
    0: "Прежде чем бороться с непослушанием — спроси себя: в каких областях ребёнок имеет реальный выбор и контроль? Часто увеличение автономии в одной области снижает сопротивление во всех остальных. Потребность в контроле над собственной жизнью — базовая человеческая потребность. Ребёнок который нигде не имеет выбора — борется за него везде. Дай ему выбирать одежду, порядок домашних дел, время прогулки — и посмотри что изменится в общем уровне сопротивления.",
    1: "Знание что за возрастным непослушанием стоит нормальная потребность в автономии снижает тревогу родителя. Это не катастрофа — это этап. Твоя задача направить а не подавить. Трёхлетний «нет» и подростковый «нет» — одна и та же потребность в разных масштабах. Ребёнок проверяет: существуют ли границы, можно ли им доверять, буду ли я принят даже когда сопротивляюсь? Твой спокойный ответ на это сопротивление — важнее содержания самого конфликта.",
    2: "Когда чувствуешь что конфликт эскалирует — ты единственный кто может остановить цикл. Не потому что ты уступаешь а потому что ты взрослый. Пауза и снижение тона — не поражение, это выход из ловушки. Эскалация работает по принципу зеркала: ты повышаешь — он повышает. Ты снижаешь тон — это разрывает цикл. Это требует огромного самоконтроля в момент когда меньше всего хочется его применять. Но именно здесь решается кто управляет ситуацией.",
    3: "Для ребёнка который «не боится наказаний» — ищи что ему реально важно и используй это как инструмент. Это не манипуляция — это поиск рычага который работает для конкретного человека. Ребёнок который не боится стандартных наказаний часто просто нашёл что наказание стоит того — или что наказание неизбежно в любом случае. Найди что он ценит: время с тобой, определённая активность, привилегия. И свяжи это с поведением через последствие.",
    4: "Определи заранее три вещи в которых компромисс невозможен. В остальном — гибкость. Это сохраняет энергию для важных битв и учит ребёнка различать принципиальное от второстепенного. Родитель который борется за всё — теряет всё. Потому что энергия и авторитет конечны. Ребёнок начинает воспринимать каждое требование как очередной повод для борьбы. Когда ты гибок в несущественном — твоя твёрдость в важном приобретает вес.",
    5: "Посчитай сколько раз сегодня ты сказал ребёнку что-то позитивное vs корректирующее. Если соотношение меньше чем 5 к 1 — ты непреднамеренно обучаешь его получать внимание через конфликт. Это не теория — это механика подкрепления. Ребёнок получает внимание когда ведёт себя хорошо? Нет — ты занят. Когда плохо? Да — ты реагируешь. Если плохое поведение стабильнее приносит твоё присутствие — мозг ребёнка это запомнит. Измени соотношение.",
    6: "Создай предсказуемые ритуалы для регулярных переходов: утренняя рутина, возвращение из школы, отход ко сну. Предсказуемость снижает сопротивление даже у самых упрямых детей — потому что убирает ощущение внезапной потери контроля. Сопротивление часто возникает не против самого действия а против внезапности. Ребёнок который знает что будет дальше — реже борется с этим. Ритуалы — это предсказуемые рельсы которые позволяют упрямому ребёнку сохранить достоинство при движении вперёд.",
    7: "Подростковое «нет» часто означает «я строю свою идентичность отдельную от тебя» — а не «я тебя ненавижу». Это болезненно — и необходимо. Твоя задача оставаться доступным когда он нуждается в поддержке — и не требовать соответствия когда он её не ищет. Подросток который полностью согласен с родителями и не сопротивляется — часто вызывает больше беспокойства чем тот кто протестует. Здоровая сепарация шумная. Тихая может означать что ребёнок отказался от себя.",
    8: "Когда стоит выбор между победой в споре и сохранением отношений — выбирай отношения. Ты можешь быть прав и проиграть всё что важно. Отношения — это счёт из которого ты черпаешь когда действительно нужно. Подросток который чувствует что родитель выбирает правоту над связью — перестаёт приходить с настоящими проблемами. Он идёт к сверстникам или интернету. Твоя способность уступить в споре — это инвестиция в то что он придёт к тебе когда будет по-настоящему трудно.",
    9: "Упрямый ребёнок часто вырастает в человека с сильным характером — если направить эту силу а не сломать её. Твоя задача не подавить а сформировать. Разница в подходе определяет кем он станет. Упрямство — это устойчивость к чужому давлению, настойчивость в достижении цели, способность отстаивать позицию. В правильном контексте это ценнейшие качества. Задача не сделать ребёнка послушным — а помочь ему направить эту силу туда где она создаёт а не разрушает.",
},
568: {
    0: "Читай ребёнку вслух не вместо обучения чтению — до него и одновременно с ним. Ты создаёшь эмоциональную связь с книгами которая мотивирует осваивать технику чтения. Ребёнок который слышал тысячи историй до того как научился читать — входит в чтение с огромным словарным запасом и пониманием нарратива. Техника чтения тогда становится ключом к миру который он уже знает и любит — а не унылым заданием без понятной цели.",
    1: "Разрыв в языковом развитии детей создаётся не деньгами — вниманием. Разговор и чтение вслух бесплатны. Это одна из немногих областей где небогатая семья может полностью компенсировать отсутствие материальных ресурсов. 30 миллионов слов к трём годам — не из дорогих игрушек. Из разговоров за едой, комментариев по дороге в магазин, чтения перед сном. Это требует времени и присутствия — не денег. Это равные возможности которые лежат в твоих руках.",
    2: "Не жди пока ребёнок «поймёт» — начни читать сразу. Ритм, интонация, звуки языка формируют мозг задолго до понимания смысла. Это инвестиция которая начинает работать немедленно. Новорождённый слышит интонацию и ритм прежде чем понимает слова. Мозг привыкает к структуре языка через повторение. Младенец которому читают с рождения к году имеет больший словарный запас чем тот которому начали читать позже. Начало раннее — результат долгосрочный.",
    3: "Не прекращай читать вслух когда ребёнок пошёл в школу. Переходи к более сложным текстам которые он сам ещё не осилит. Это сохраняет ритуал и поднимает планку того что он считает «хорошей книгой». Дети которым читают вслух в начальной школе понимают сложные тексты лучше сверстников. Потому что слушание обгоняет чтение по уровню сложности которую можно обработать. Читай ему то что он не осилит сам — и расширяй горизонт того что кажется ему возможным.",
    4: "Регулярные походы в библиотеку с ребёнком — один из самых простых вкладов в его читательское развитие. Дай ему выбирать самому — даже если он выбирает «неправильные» книги. Любая книга которую он выбрал сам лучше правильной книги которую он читает из-под палки. Автономия в выборе книг создаёт читателей. Отсутствие автономии создаёт людей которые бросают чтение как только исчезает внешнее требование. Твоя задача не подобрать правильный список — а зажечь.",
    5: "Ограничение экранного времени — не наказание и не отставание от современности. Это создание пространства для деятельности которая тренирует мозг активно. Скука после выключения телевизора — начало чтения. Скука — не проблема которую нужно заполнить. Это состояние в котором мозг ищет активность. Ребёнок которому скучно без экрана часто сам тянется к книге. Не потому что ты заставил — а потому что мозг предпочитает историю пустоте. Создай пространство — и книга придёт сама.",
    6: "Не снобируй детское чтение. Ребёнок который глотает книги о Гарри Поттере или детективы без остановки — читает. Это главное. Литературные вкусы развиваются через количество прочитанного а не через качество первых книг. Читатель который начал с «неправильных» книг и полюбил чтение — в конечном счёте прочитает и «правильные». Нечитатель который получил «правильные» книги через принуждение — не прочитает ничего. Поддерживай то что уже горит — остальное придёт.",
    7: "Выбирай книги для чтения вслух с учётом того через что проходит ребёнок. Книга о потере, о страхе, о несправедливости — открывает разговор который ребёнок иначе не начнёт. Художественный текст как вход в сложный разговор. Персонаж книги даёт ребёнку дистанцию — он может говорить о Гарри Поттере и говорить о себе одновременно. Это безопаснее чем прямой вопрос. Книга которую вы читаете вместе становится общим языком для тем которые иначе не называются.",
    8: "Лучшие образовательные движения начинались с одного учителя который был убеждён что нашёл что-то важное — и не ждал разрешения системы чтобы об этом говорить. Ты тоже не ждёшь разрешения. 20 минут вслух перед сном не требуют ни согласия школы ни специального образования. Это доступно прямо сейчас. Один человек — один ребёнок — одна книга каждый вечер. Это то из чего вырастают читающие люди. И это полностью в твоих руках.",
    9: "20 минут вслух перед сном — это не много. Это меньше одного эпизода сериала. И это одна из наиболее эффективных вещей которую ты можешь делать для будущего ребёнка каждый день. Суммарно за год это больше 120 часов совместного чтения. За 10 лет — больше 1200 часов историй, словарного запаса, близости и любви к книгам. Это не подвиг — это привычка. Привычки которые начаты рано и поддерживаются стабильно меняют жизнь без усилий.",
},
}

count = 0
for b in books:
    bid = b.get("id")
    if bid in updates:
        for i, t in enumerate(b.get("thoughts", [])):
            if i in updates[bid]:
                new_life = updates[bid][i]
                ex = t["example"]
                life_start = ex.find("\n\n**В жизни:**")
                if life_start >= 0:
                    t["example"] = ex[:life_start] + "\n\n**В жизни:** " + new_life
                    count += 1

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",", ":"))
print(f"Updated {count} thoughts")
